{
  "object_animations": {
    "evidence_gate": {
      "description": "The Evidence Gate is the central interface through which traders and portfolio managers interact with the decision-making process. It visually represents the filtering, challenge, approval, and recording of market evidence. The gate opens and closes in sync with the approval process, and its surface is dynamically updated with real-time data and visual indicators of evidence status.",
      "animations": [
        {
          "name": "evidence_gate_open",
          "trigger": "approval_stage_complete",
          "motion": {
            "type": "rotation",
            "axis": "z",
            "start": 0,
            "end": 360,
            "duration": 2.5,
            "easing": "easeInOutQuad"
          },
          "camera": {
            "type": "follow",
            "target": "evidence_gate",
            "distance": 10,
            "height": 2,
            "fov": 55
          },
          "visuals": {
            "lighting": {
              "type": "spotlight",
              "position": [0, 5, -5],
              "intensity": 0.8,
              "angle": 45
            },
            "surface": {
              "material": "glass",
              "color": "#0066cc",
              "transparency": 0.7,
              "reflection": "high"
            }
          }
        },
        {
          "name": "evidence_gate_close",
          "trigger": "approval_stage_failed",
          "motion": {
            "type": "rotation",
            "axis": "z",
            "start": 360,
            "end": 0,
            "duration": 2.5,
            "easing": "easeInOutQuad"
          },
          "camera": {
            "type": "follow",
            "target": "evidence_gate",
            "distance": 10,
            "height": 2,
            "fov": 55
          },
          "visuals": {
            "lighting": {
              "type": "spotlight",
              "position": [0, 5, -5],
              "intensity": 0.8,
              "angle": 45
            },
            "surface": {
              "material": "glass",
              "color": "#ff6666",
              "transparency": 0.7,
              "reflection": "high"
            }
          }
        },
        {
          "name": "evidence_gate_update",
          "trigger": "evidence_status_change",
          "motion": {
            "type": "surface_update",
            "elements": [
              {
                "type": "icon",
                "position": [0, 0, 0],
                "icon": "evidence_icon",
                "color": "#00ffcc",
                "scale": 1.2
              },
              {
                "type": "text",
                "position": [0, -1, 0],
                "text": "Evidence Approved",
                "font": "monospace",
                "size": 0.8
              }
            ]
          },
          "camera": {
            "type": "static",
            "position": [0, 5, 10],
            "fov": 55
          },
          "visuals": {
            "lighting": {
              "type": "ambient",
              "intensity": 0.9
            }
          }
        }
      ]
    },
    "evidence_icon": {
      "description": "A dynamic icon that represents the status of an individual piece of evidence. It changes color and shape based on its validation status (e.g., pending, approved, rejected).",
      "animations": [
        {
          "name": "evidence_icon_pending",
          "trigger": "evidence_status_pending",
          "motion": {
            "type": "color_change",
            "start": "#ffcc00",
            "end": "#ffcc00",
            "duration": 1.0
          }
        },
        {
          "name": "evidence_icon_approved",
          "trigger": "evidence_status_approved",
          "motion": {
            "type": "color_change",
            "start": "#00ccff",
            "end": "#00ccff",
            "duration": 1.0
          }
        },
        {
          "name": "evidence_icon_rejected",
          "trigger": "evidence_status_rejected",
          "motion": {
            "type": "color_change",
            "start": "#ff6666",
            "end": "#ff6666",
            "duration": 1.0
          }
        }
      ]
    },
    "risk_indicator": {
      "description": "A visual indicator that shows the risk level of a decision. It pulses or changes scale based on the confidence and risk profile of the evidence.",
      "animations": [
        {
          "name": "risk_indicator_low",
          "trigger": "risk_level_low",
          "motion": {
            "type": "scale",
            "start": 1.0,
            "end": 1.2,
            "duration": 1.5,
            "easing": "easeInOutSine"
          }
